 ```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-like Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  body {
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
    background: #000;
  }
  #desktop {
    position: absolute;
    inset: 0;
    background: radial-gradient(circle at 50% 30%, #2c1e4a 0%, #0f0f1a 60%, #050505 100%);
    overflow: hidden;
  }
  #taskbar {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 40px;
    background: rgba(30, 30, 30, 0.95);
    border-bottom: 1px solid #333;
    display: flex;
    align-items: center;
    padding: 0 12px;
    gap: 10px;
    color: #fff;
    z-index: 1000;
  }
  #taskbar button {
    background: #333;
    border: 1px solid #444;
    color: #fff;
    padding: 5px 12px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 13px;
  }
  #taskbar button:hover { background: #444; }
  .taskbar-title { margin-left: auto; font-weight: 500; opacity: 0.9; font-size: 13px; }
  #clock { font-variant-numeric: tabular-nums; opacity: 0.8; font-size: 13px; min-width: 60px; text-align: right; }

  .window {
    position: absolute;
    display: none;
    flex-direction: column;
    min-width: 360px;
    min-height: 240px;
    width: 720px;
    height: 480px;
    background: #252525;
    border: 1px solid #444;
    border-radius: 10px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.6);
    overflow: hidden;
    color: #eee;
  }
  .win-titlebar {
    height: 36px;
    background: #333;
    display: flex;
    align-items: center;
    padding: 0 12px;
    cursor: default;
    user-select: none;
  }
  .win-title { flex: 1; font-weight: 600; font-size: 14px; }
  .win-close {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    border: none;
    background: #e81123;
    color: #fff;
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .win-close:hover { background: #ff1a2e; }
  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    padding: 10px;
    gap: 8px;
  }

  .files-toolbar { display: flex; align-items: center; gap: 10px; }
  #files-up {
    padding: 4px 10px;
    background: #3a3a3a;
    border: 1px solid #555;
    color: #fff;
    border-radius: 5px;
    cursor: pointer;
  }
  #files-up:hover { background: #484848; }
  #files-path {
    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
    color: #aaa;
    font-size: 13px;
  }
  #files-list {
    flex: 1;
    overflow: auto;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    gap: 12px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 10px;
    border-radius: 8px;
    cursor: pointer;
    text-align: center;
    word-break: break-word;
    font-size: 12px;
    color: #ddd;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item::before {
    content: "📄";
    font-size: 32px;
    margin-bottom: 4px;
    color: #bbb;
  }
  .fs-item.folder::before { content: "📁"; color: #f4d03f; }

  .tabs { display: flex; gap: 4px; overflow-x: auto; }
  .tab {
    padding: 6px 12px;
    background: #333;
    border: 1px solid #444;
    border-radius: 6px 6px 0 0;
    cursor: pointer;
    color: #ccc;
    font-size: 13px;
    white-space: nowrap;
  }
  .tab:hover { background: #3d3d3d; }
  .tab.active { background: #4a4a4a; color: #fff; border-color: #666; }
  #new-tab {
    align-self: flex-start;
    padding: 5px 10px;
    background: #3a3a3a;
    border: 1px solid #555;
    color: #fff;
    border-radius: 5px;
    cursor: pointer;
  }
  #new-tab:hover { background: #484848; }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    background: #1e1e1e;
    color: #eee;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 10px;
    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
    font-size: 14px;
    outline: none;
  }
  #editor:focus { border-color: #777; }
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
    <span class="taskbar-title">Ubuntu-like Desktop</span>
    <span id="clock"></span>
  </div>

  <div id="files-window" class="window" style="top: 70px; left: 60px;">
    <div class="win-titlebar">
      <span class="win-title">Files</span>
      <button class="win-close">×</button>
    </div>
    <div class="win-body">
      <div class="files-toolbar">
        <button id="files-up">Up</button>
        <span id="files-path">/</span>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <div id="notepad-window" class="window" style="top: 110px; left: 120px;">
    <div class="win-titlebar">
      <span class="win-title">Notepad</span>
      <button class="win-close">×</button>
    </div>
    <div class="win-body">
      <div id="tabs" class="tabs"></div>
      <button id="new-tab">+ New Tab</button>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
(function() {
  // --- Window management ---
  const desktop = document.getElementById('desktop');
  const windows = document.querySelectorAll('.window');
  let topZ = 10;

  function bringToFront(win) {
    win.style.zIndex = ++topZ;
  }

  function showWindow(id) {
    const win = document.getElementById(id);
    if (!win) return;
    win.style.display = 'flex';
    bringToFront(win);
  }

  function hideWindow(win) {
    win.style.display = 'none';
  }

  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', e => {
      e.stopPropagation();
      hideWindow(btn.closest('.window'));
    });
  });

  document.getElementById('open-files').addEventListener('click', () => {
    showWindow('files-window');
    renderFiles();
  });
  document.getElementById('open-notepad').addEventListener('click', () => {
    showWindow('notepad-window');
    renderTabs();
    updateEditor();
  });

  windows.forEach(win => {
    win.addEventListener('mousedown', () => bringToFront(win));
  });

  // Dragging
  let drag = null;
  document.querySelectorAll('.win-titlebar').forEach(bar => {
    bar.addEventListener('mousedown', e => {
      if (e.target.closest('.win-close')) return;
      const win = bar.closest('.window');
      bringToFront(win);
      drag = {
        win,
        offsetX: e.clientX - win.offsetLeft,
        offsetY: e.clientY - win.offsetTop
      };
    });
  });
  document.addEventListener('mousemove', e => {
    if (!drag) return;
    let x = e.clientX - drag.offsetX;
    let y = e.clientY - drag.offsetY;
    const maxX = desktop.clientWidth - drag.win.offsetWidth;
    const maxY = desktop.clientHeight - drag.win.offsetHeight;
    if (x < 0) x = 0;
    if (y < 0) y = 0;
    if (x > maxX) x = maxX;
    if (y > maxY) y = maxY;
    drag.win.style.left = x + 'px';
    drag.win.style.top = y + 'px';
  });
  document.addEventListener('mouseup', () => { drag = null; });

  // Clock
  function updateClock() {
    const now = new Date();
    document.getElementById('clock').textContent = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 1000);

  // --- Files app ---
  const fsData = {
    type: 'root',
    children: [
      { name: 'bin', type: 'folder', children: [
        { name: 'bash', type: 'file' },
        { name: 'ls', type: 'file' },
        { name: 'cat', type: 'file' }
      ]},
      { name: 'etc', type: 'folder', children: [
        { name: 'passwd', type: 'file' },
        { name: 'hosts', type: 'file' }
      ]},
      { name: 'home', type: 'folder', children: [
        { name: 'user', type: 'folder', children: [
          { name: 'Documents', type: 'folder', children: [
            { name: 'resume.txt', type: 'file' },
            { name: 'project', type: 'folder', children: [
              { name: 'main.js', type: 'file' }
            ]}
          ]},
          { name: 'Downloads', type: 'folder', children: [
            { name: 'file.zip', type: 'file' }
          ]},
          { name: 'Pictures', type: 'folder', children: [
            { name: 'wallpaper.png', type: 'file' }
          ]},
          { name: 'notes.txt', type: 'file' }
        ]}
      ]},
      { name: 'usr', type: 'folder', children: [
        { name: 'bin', type: 'folder', children: [
          { name: 'gcc', type: 'file' }
        ]},
        { name: 'share', type: 'folder', children: [
          { name: 'themes', type: 'folder' }
        ]}
      ]},
      { name: 'var', type: 'folder', children: [
        { name: 'log', type: 'folder', children: [
          { name: 'syslog', type: 'file' }
        ]}
      ]}
    ]
  };

  let currentPath = '/';

  function getNode(path) {
    if (path === '/') return fsData;
    const parts = path.split('/').filter(Boolean);
    let node = fsData;
    for (const part of parts) {
      if (!node.children) return null;
      node = node.children.find(c => c.name === part && c.type === 'folder');
      if (!node) return null;
    }
    return node;
  }

  function renderFiles() {
    const node = getNode(currentPath);
    const list = document.getElementById('files-list');
    const pathEl = document.getElementById('files-path');
    list.innerHTML = '';
    pathEl.textContent = currentPath;
    if (!node || !node.children) return;
    node.children.forEach(child => {
      const el = document.createElement('div');
      el.className = 'fs-item ' + child.type;
      el.textContent = child.name;
      if (child.type === 'folder') {
        el.addEventListener('dblclick', () => {
          currentPath = currentPath === '/' ? '/' + child.name : currentPath + '/' + child.name;
          renderFiles();
        });
      }
      list.appendChild(el);
    });
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/');
    renderFiles();
  });

  // --- Notepad app ---
  const STORAGE_KEY = 'notepad-tabs';
  const tabsEl = document.getElementById('tabs');
  const editor = document.getElementById('editor');
  let tabs = [];
  let activeId = null;

  function generateId() {
    return Date.now().toString(36) + Math.random().toString(36).slice(2);
  }

  function saveTabs() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
    } catch (e) {}
  }

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed) && parsed.length > 0) return parsed;
      }
    } catch (e) {}
    return [{ id: generateId(), name: 'Untitled 1', content: '', active: true }];
  }

  function renderTabs() {
    tabsEl.innerHTML = '';
    tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === activeId ? ' active' : '');
      el.textContent = tab.name;
      el.addEventListener('click', () => setActiveTab(tab.id));
      tabsEl.appendChild(el);
    });
  }

  function updateEditor() {
    const tab = tabs.find(t => t.id === activeId);
    editor.value = tab ? tab.content : '';
  }

  function setActiveTab(id) {
    activeId = id;
    tabs.forEach(t => t.active = (t.id === id));
    renderTabs();
    updateEditor();
    saveTabs();
  }

  document.getElementById('new-tab').addEventListener('click', () => {
    const count = tabs.filter(t => t.name.startsWith('Untitled')).length + 1;
    const tab = { id: generateId(), name: 'Untitled ' + count, content: '', active: false };
    tabs.push(tab);
    setActiveTab(tab.id);
  });

  editor.addEventListener('input', () => {
    const tab = tabs.find(t => t.id === activeId);
    if (tab) {
      tab.content = editor.value;
      saveTabs();
    }
  });

  function initNotepad() {
    tabs = loadTabs();
    const active = tabs.find(t => t.active);
    activeId = active ? active.id : tabs[0].id;
    tabs.forEach(t => t.active = (t.id === activeId));
    saveTabs();
    renderTabs();
    updateEditor();
  }

  initNotepad();
})();
</script>
</body>
</html>
